  ('optometrist-moex-02474', 'optometrist', 'optometrist-moex-108-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '測量一平頂雙光鏡片的數值如下：子片寬度（seg width）：30 mm，子片深度（seg depth）：18 mm，加 入度：+2.00 D。此鏡片會產生的像跳量（image jump）為何？', '["0.6△，基底朝下", "1.2△，基底朝下", "2.4△，基底朝下", "3.6△，基底朝下"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:52+00:00", "source_pdf_sha1": "879d402a916a", "answer_pdf_sha1": "60102628a2c1", "source_family": "moex-gov-tw", "moex": {"exam_code": "108060", "c": "401", "s": "0804", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "108", "exam_name": "108年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 50, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
